B = (0,0);
C = (14,0);
P = (c^2*a^2*A + a^2*b^2*B + b^2*c^2*C)/(c^2*a^2 + a^2*b^2 + b^2*c^2);

draw(anglemark(B,A,P,40),red); 
draw(anglemark(C,B,P,40),red); 
draw(anglemark(A,C,P,40),red); 
draw(A--B--C--cycle);
draw(A--P);
draw(B--P);
draw(C--P);

label("$A$", A, N);
label("$B$", B, SW);
label("$C$", C, SE);
label("$P$", P, NE);
label("$13$", (A + B)/2, NW);
label("$14$", (B + C)/2, S);
label("$15$", (A + C)/2, NE);

label("$x$", (A + P)/2, W);
label("$y$", (B + P)/2, NW);
label("$z$", (C + P)/2, NE);
[/asy]

